            ]
          },
          {
            "name": "db",
            "dependencies": [
              "daemon",
              "p2p"
            ]
          },
          {
            "name": "daemon",
            "dependencies": []
          },
          {
            "name": "p2p",
            "dependencies": []
          }
        ]
      },
      "expected_output": "order=[\"daemon\",\"p2p\",\"db\",\"chain\"]\n"
    }
  ]
}
